solution_code:
#include <iostream>

void reverseArray(int* arr, int size) {
    for (int i = 0; i < size / 2; ++i) {
        int tmp = arr[i];
        arr[i] = arr[size - 1 - i];
        arr[size - 1 - i] = tmp;
    }
}

int main() {
    int n;
    std::cin >> n;
    int* arr = new int[n];
    for (int i = 0; i < n; ++i)
        std::cin >> arr[i];

    reverseArray(arr, n);

    for (int i = 0; i < n; ++i) {
        if (i > 0) std::cout << " ";
        std::cout << arr[i];
    }
    std::cout << "\n";

    delete[] arr;
    return 0;
}
